changeSet.sql:
ALTER TABLE chat
    ADD CONSTRAINT fk_chat_participant_one
        FOREIGN KEY (participant_one) REFERENCES user_profile (id);

ALTER TABLE chat
    ADD CONSTRAINT fk_chat_participant_two
        FOREIGN KEY (participant_two) REFERENCES user_profile (id);

ALTER TABLE chat
    ADD CONSTRAINT uq_chat_participants_listing
        UNIQUE (participant_one, participant_two, listing_id);

ALTER TABLE chat
    ADD CONSTRAINT chk_chat_participant_order
        CHECK (participant_one < participant_two);
